def _resolve_dynamic_defaults(self, ctx: Context) -> None:
    """Second-pass resolution for options whose default is a mapping
    of other option values to the actual default value. Runs after all
    parameters have been parsed so the referenced option values are
    final, and only applies to options whose value still comes from
    their own (unresolved) default.
    """
    params = self.get_params(ctx)

    for param in params:
        if not isinstance(param, Option) or param._dynamic_default is None:
            continue

        if ctx.get_parameter_source(param.name) is not ParameterSource.DEFAULT:  # type: ignore
            continue

        resolved = None

        for opt_name, mapping in param._dynamic_default.items():
            source_param = next(
                (
                    p
                    for p in params
                    if opt_name in p.opts or opt_name in p.secondary_opts
                ),
                None,
            )

            if source_param is None:
                continue

            key = str(ctx.params.get(source_param.name))

            if key in mapping:
                resolved = mapping[key]

        if resolved is not None:
            ctx.params[param.name] = param.type_cast_value(ctx, resolved)  # type: ignore

